setMockDbVocabularyWords(
  mockVocabularyWords.map(word => ({
    ...word,
    accountId: activeAccount.id,
    userId: activeUser.id,
    lessonId: word.id === '1' ? '1' : word.id === '2' ? '2' : undefined,
  })),
);

export const mockReviewWords = [
  ...mockDb.reviewWords
    .filter(
      word =>
        word.accountId === activeAccount.id && word.userId === activeUser.id,
    )
    .map(({ id: _id, accountId: _accountId, userId: _userId, ...word }) => word),
] as const;
