import type { QuizQuestionDto, ScheduledLessonDto, VocabularyWordDto } from '@soenglish/shared-types';
import type { MockLesson } from './domains/lessons';
import type { ProfileStats } from './domains/achievements';

export type UserRole = 'student' | 'teacher' | 'admin' | 'super-admin';

export type AccountRecord = {
  id: string;
  slug: string;
  name: string;
  status: 'active' | 'inactive';
};

export type UserRecord = {
  id: string;
  accountId: string;
  fullName: string;
  email: string;
  role: UserRole;
  avatarInitials: string;
  targetLevel: string;
  streakDays: number;
};

export type ProfileRecord = {
  id: string;
  accountId: string;
  userId: string;
  telegram: string;
  phone: string;
  timezone: string;
  nativeLanguage: string;
  weeklyGoal: string;
  bio: string;
};

export type ProfileMetaRecord = {
  id: string;
  accountId: string;
  userId: string;
  status: 'active' | 'paused';
  scheduleType: 'fixed' | 'flexible';
  teacherId: string;
  notes: string;
  calendarColor?: string;
};

export type ProfileGoalRecord = {
  id: string;
  accountId: string;
  userId: string;
  text: string;
  done: boolean;
};

export type PracticeActivityRecord = {
  id: string;
  accountId: string;
  href: string;
  title: string;
  description: string;
  icon: string;
  tag: string;
  tagClass: 'tagGreen' | 'tagBlue' | 'tagAmber' | 'tagMuted';
  disabled?: boolean;
};

export type SessionRecord = {
  id: string;
  accountId: string;
  userId: string;
  role: UserRole;
};

export type ReviewWordRecord = {
  id: string;
  accountId: string;
  userId: string;
  word: string;
  pos: string;
  def: string;
  status: 'new' | 'learning' | 'known';
};

export type VocabularyWordRecord = VocabularyWordDto & {
  accountId: string;
  userId: string;
  lessonId?: string;
};

type MockDb = {
  accounts: AccountRecord[];
  users: UserRecord[];
  profiles: ProfileRecord[];
  profileMeta: ProfileMetaRecord[];
  profileStats: Array<ProfileStats & { accountId: string; userId: string }>;
  profileGoals: ProfileGoalRecord[];
  practiceActivities: PracticeActivityRecord[];
  sessions: SessionRecord[];
  lessons: Array<MockLesson & { accountId: string }>;
  scheduledLessons: Array<ScheduledLessonDto & { accountId: string }>;
  vocabularyWords: VocabularyWordRecord[];
  reviewWords: ReviewWordRecord[];
  quizQuestions: Array<QuizQuestionDto & { accountId: string; userId: string }>;
};

