export const setMockDbLessons = (lessons: MockDb['lessons']) => {
  mockDb.lessons = lessons;
};

export const setMockDbScheduledLessons = (scheduledLessons: MockDb['scheduledLessons']) => {
  mockDb.scheduledLessons = scheduledLessons;
};

export const setMockDbVocabularyWords = (vocabularyWords: VocabularyWordRecord[]) => {
  mockDb.vocabularyWords = vocabularyWords;
};

export const setMockDbQuizQuestions = (quizQuestions: MockDb['quizQuestions']) => {
  mockDb.quizQuestions = quizQuestions;
};

export const setMockDbSessions = (sessions: SessionRecord[]) => {
  mockDb.sessions = sessions;
};

const byId = <T extends { id: string }>(rows: T[]) =>
  rows.reduce<Record<string, T>>((acc, row) => {
    acc[row.id] = row;
    return acc;
  }, {});

export const mockDbIndexes = {
  get usersById() {
    return byId(mockDb.users);
  },
  get accountsById() {
    return byId(mockDb.accounts);
  },
};

export const getDefaultStudentId = () => defaultStudentId;
